import sensors from '@/utils/sensors';

/**
 *
 * @param type 密码验证页面_选择设备页面
 * 显示的可操作设备数量。如果没有则是0
 */
export const password_device_show = (device_num: number) => {
  sensors.track('password_device_show', {
    device_num
  });
};

/**
 *
 * @param type 开启密码验证的场景
 * 开启的场景
    screen 屏幕解锁
    factoryreset 恢复出厂设置
 */
export const password_scene_open = (type: string) => {
  sensors.track('password_scene_open', {
    type
  });
};

/**
 *
 * @param type 关闭密码验证的场景
 * 
 * 关闭的场景
    screen 屏幕解锁
    factoryreset 恢复出厂设置
 */
export const password_scene_close = (type: string) => {
  sensors.track('password_scene_close', {
    type
  });
};

/**
 * 密码验证功能开启
 */
export const password_open = () => {
  sensors.track('password_open');
};

/**
 * 密码验证功能关闭
 */
export const password_close = () => {
  sensors.track('password_close');
};

