import ApiService, { ResponseType } from '@/api/api';
import { getTokenByBridge, getUrlParamNew } from '@/utils';

type IncentiveDetailType = ResponseType<{
  total: string;
  exp_label_url: string;
  tips_version: string;
  list: {
    device_sn: string;
    login_desc: string;
  }[];
}>;

const getUserInfo = (): Promise<any> => {
  return new Promise((resolve) => {
    window.ConnectWebViewBridgeSDK.getUserInfo(
      (data: Record<string, string>) => {
        resolve(data);
      }
    );
    setTimeout(() => {
      resolve({});
    }, 1000);
  });
};

export const getDeviceList = async (): IncentiveDetailType => {
  const token = await getTokenByBridge();
  return ApiService.post('/parent/api/v1/device/config/device-list', {
    token
  });
};

/**
 *
 * @param params
 * @returns
 * key 支持批量，用英文逗号隔开
 */
export const getDeviceConfig = async (params: {
  key: string;
  sn: string;
  bus_bu: number;
}) => {
  const token = await getTokenByBridge();
  return ApiService.post('/parent/api/v1/device/config/list', {
    ...params,
    token
  });
};

export const setDeviceConfigs = async (params: {
  set_list: {
    key: string;
    value: string;
  }[];
  sn: string;
  bus_bu: number;
}) => {
  const token = await getTokenByBridge();
  return ApiService.post('/parent/api/v1/device/config/batch-set', {
    ...params,
    token
  });
};
